            &.inactive {
              color: #c2c8cc;
            }
          }
        }
      }
      &-content {
        margin: 0 0 40px 0;
        line-height: 35px;
      }
      &-author {
        margin: 0 0 0 35px;
        color: #7e7e8a;
        font-size: 16px;

